/* gamedata-w7-clamwork.mjs — Clam Work / "The Clamworks" (W7 active minigame with Mr. Musselini),
 * extracted verbatim from N.js. GENERATED by a one-off extraction script (scratchpad, not
 * committed); refresh after a major patch.
 *
 * WHY THIS FILE EXISTS: `Thingies("ClamWorkBonus",b,0)` had NO evaluator anywhere in the repo —
 * bonuses/summoning.mjs::meritocBonusz stubs it `clamWorkBonus: 0` (comment: "ClamWorkBonus(3)
 * unread -> floor"), and bonuses/ballot.mjs's Meritocracy note references the same gap. This file
 * supplies BOTH the full formula set (all "Clam_*"/"ClamWorkBonus"/"ClamBonuses"/"Clamz_*" cases,
 * a closed system, no unread inputs) and the upgrade + job-reward tables.
 *
 * DISPATCHER: same `m._customBlock_Thingies=function(d,b,e)` as gamedata-w7-zenith.mjs (N.js byte
 * 10698460). All Clam cases live contiguously at N.js byte ~10706800-10709500 (dumped and
 * transcribed end-to-end, not sampled).
 *
 * SURPRISE #1 — ClamWorkBonus IS NOT A PERCENT. N.js byte 10709318, verbatim:
 *   "ClamWorkBonus"==d) return OptLacc[464] > b ? 1 : 0
 * It's a boolean gate: 1 iff the account's Clam Work JOB LEVEL (OptionsListAccount[464]) is
 * STRICTLY GREATER than the argument `b`, else 0. Every caller in the client multiplies this by
 * a fixed weight (e.g. bonuses/summoning.mjs's meritocBonusz uses `5*ClamWorkBonus(3)`,
 * bonuses/holes.mjs-adjacent code elsewhere uses `20*ClamWorkBonus(5)`) — the "5*"/"20*" is NOT
 * part of ClamWorkBonus itself, it's baked into each caller's own formula. This resolves the
 * bonuses/summoning.mjs stub exactly (`clamWorkBonus: 0` should become
 * `OptLacc[464] > 3 ? 1 : 0`, not a percent lookup).
 *
 * SURPRISE #2 — "the clam work upgrade table" is Ya.Spelunky() rows 27/28/29 (a giant multi-
 * system CustomLists literal — see gamedata-w7-spelunking.mjs's header for the full row map),
 * NOT a standalone Ya.ClamWork table (grepped for `.ClamWork\w*=function` and every `*Clam*`
 * identifier in N.js — no such table exists). `ClamBonuses(b)` reads
 * `CustomLists.Spelunky[28][b] * OptionsListAccount[b+455]` (upgrade LEVEL lives at
 * OptLacc[455..463], one slot per upgrade id 0..8).
 *
 * Full formula set, N.js byte ~10706800-10709500, verbatim (OLA = OptionsListAccount, the save's
 * account-options array; `wb = WorkbenchStuff`):
 *   ClamBonuses(b) =
 *     999==b ? 1
 *     : 3==b ? WorkbenchStuff("MultiKillTOTAL",0,0)/1000 * CLAM_UPG[b].coeff * OLA[b+455]
 *     : CLAM_UPG[b].coeff * OLA[b+455]
 *   ClamPearlValue() = (1+ClamBonuses(0)) * (1+ClamBonuses(3)/100) * (1+ClamBonuses(7)/100)
 *   ClamPearl10x()  = random() < 1 - 1/(1+ClamBonuses(2)/100) ? 10 : 1
 *   Clam_BlackPearlValue() = 50 + ClamBonuses(5)
 *   Clam_PearlUpgReq(b) = 20 * Math.pow(10 + 3*OLA[464], b-1)      // OLA[464] = job level
 *   Clam_Cost(b) =
 *     9==b ? 1e5 * Math.pow(10, OLA[464])                          // JOB PROMOTION cost
 *     : (1/(1+ClamBonuses(4)/100)) * (1/(1+ClamBonuses(8)/100)) * (
 *         0==b
 *           ? Math.pow(CLAM_UPG[b].costGrowth, OLA[b+455]) + (3*OLA[b+455] + Math.pow(OLA[b+455], 2.5))
 *           : (Clam_PearlUpgReq(b)/5) * Math.pow(CLAM_UPG[b].costGrowth, OLA[b+455])
 *               + (2*OLA[b+455] + Math.pow(OLA[b+455], 1.5))
 *       )
 *   Clam_Mobs()    = min(25, 2 + OLA[456])                          // upgrade 1's level, reused
 *   Clam_Respawn() = 60                                             // constant, seconds
 *   ClamWorkBonus(b) = OLA[464] > b ? 1 : 0                         // see SURPRISE #1
 *   Clamz_HP()     = 1e16 * Math.pow(30, OLA[464])                  // scales with job level
 *   ClamPromochance() = 0.5 / (2 + OLA[464])                        // chance to promote a job tier
 * OLA[454] is the "pearls saved toward next promotion" counter (spent by ClamPromochance's roll);
 * OLA[455..463] are the 9 CLAM_UPG levels; OLA[464] is the job level (0-9, gates ClamWorkBonus
 * AND scales Clamz_HP/Clam_Cost); OLA[465] is reset alongside 455-463 on promotion (purpose not
 * traced further — a per-job scratch counter). Evidence for the promotion reset: N.js byte
 * ~12545195, the "Mr. Musselini" promotion dialogue handler zeroes OLA[454..463,465] and
 * increments OLA[464] on a successful ClamPromochance roll.
 *
 * CLAM_UPG — Ya.Spelunky()[27] (names), [28] (coeff), [29] (cost growth rate); N.js byte
 * 14007601 (`return[` start), same giant literal as gamedata-w7-spelunking.mjs. 9 rows (upgrade
 * ids 0-8, OptLacc[455+id]).
 *
 * CLAM_JOB_REWARDS — Ya.Spelunky()[30], same literal, 9 entries — the reward text shown at each
 * of the 9 job PROMOTIONS (OLA[464] 0->1 .. 8->9). Cross-checked: index 1 "+1_Legend_Talent_PTS"
 * and index 4 "+1_Legend_Talent_PTS" both read as Legend Talent point grants — plausible given
 * Clam Work is an endgame W7 system feeding the Legend Talent economy.
 * -------------------------------------------------------------------------------------------- */

/** Ya.Spelunky()[27]/[28]/[29], verbatim. Index = the Clam Work upgrade id (OptLacc[455+id]). */
export const CLAM_UPG = [
  { name: "Pearl_Value",         coeff: 1,  costGrowth: 1.20, desc: "Pearls_you_find_are_worth_$_instead_of_just_1" },
  { name: "More_Clams",          coeff: 1,  costGrowth: 5.0,  desc: "Increases_the_total_number_of_clams_on_the_map_to_$" },
  { name: "Pearl_10x_Chance",    coeff: 3,  costGrowth: 1.50, desc: "Pearls_have_a_$%_chance_to_be_worth_10x_when_picked_up!" },
  { name: "Multikill_Pearl",     coeff: 1,  costGrowth: 1.4,  desc: "Boosts_pearl_value_based_on_your_Multikill!_Currently_gives_}x" },
  { name: "Cheaper_Upgrades_I",  coeff: 12, costGrowth: 1.15, desc: "All_upgrades_are_$%_cheaper" },
  { name: "Black_Pearl_Value",   coeff: 50, costGrowth: 1.5,  desc: "Clams_now_drop_pure_pearls!_These_are_worth_$x_more_than_normal!" },
  { name: "Pearl_Drop_Rate",     coeff: 10, costGrowth: 1.35, desc: "Boosts_the_drop_rate_of_pearls_by_}x" },
  { name: "Pearl_Value_II",      coeff: 10, costGrowth: 1.25, desc: "Increases_the_value_of_all_pearls_found_by_}x" },
  { name: "Cheaper_Upgrades_II", coeff: 16, costGrowth: 1.22, desc: "All_upgrades_are_}x_cheaper" },
];

/** Ya.Spelunky()[30], verbatim. Index = job level reached (0..8, promotion 0->1 .. 8->9). */
export const CLAM_JOB_REWARDS = [
  "+1_Grade_for_2_Gallery_Slots",
  "+1_Legend_Talent_PTS",
  "+10_LV/day_for_Kattlekruk_bubbles",
  "+5%_Meritocracy_Multi_bonus",
  "+1_Legend_Talent_PTS",
  "+20%_extra_Daily_Coral",
  "+15_LV/day_from_Brain_Coral",
  "+3%_Gallery_Bonus_Multi",
  "}x_Class_EXP_multi",
];

/** ClamWorkBonus(b) — a THRESHOLD GATE, not a percent (see SURPRISE #1 above). */
export const clamWorkBonusGate = (jobLevel, b) => (Number(jobLevel ?? 0) > b ? 1 : 0);

/** ClamBonuses(b) — plain level*coeff except b==3 (gated by WorkbenchStuff MultiKillTOTAL, out of
 *  scope for this file; pass it in). `upgLevel` = OptLacc[b+455]. */
export function clamBonuses(b, upgLevel, multiKillTotal = null) {
  if (b === 999) return 1;
  const row = CLAM_UPG[b];
  if (!row) throw new Error(`ClamBonuses(${b}): no CLAM_UPG row`);
  const base = row.coeff * Number(upgLevel ?? 0);
  if (b === 3) {
    if (multiKillTotal == null) throw new Error("ClamBonuses(3) needs WorkbenchStuff(\"MultiKillTOTAL\",0,0)");
    return (multiKillTotal / 1000) * base;
  }
  return base;
}

/** Clam_Cost(b, jobLevel, upgLevel) — the pearl cost to buy the NEXT level of upgrade b.
 *  Does not apply the ClamBonuses(4)/(8) discount multipliers (callers needing the exact buy
 *  price should apply `1/(1+clamBonuses(4,...)/100) * 1/(1+clamBonuses(8,...)/100)`). */
export function clamPearlUpgReq(b, jobLevel) {
  return 20 * Math.pow(10 + 3 * Number(jobLevel ?? 0), b - 1);
}
export function clamUpgCostRaw(b, jobLevel, upgLevel) {
  const row = CLAM_UPG[b];
  if (!row) throw new Error(`Clam_Cost(${b}): no CLAM_UPG row`);
  const lvl = Number(upgLevel ?? 0);
  if (b === 0) return Math.pow(row.costGrowth, lvl) + (3 * lvl + Math.pow(lvl, 2.5));
  return (clamPearlUpgReq(b, jobLevel) / 5) * Math.pow(row.costGrowth, lvl) + (2 * lvl + Math.pow(lvl, 1.5));
}

/** Clam_Cost(9, jobLevel) — job PROMOTION cost (pearls saved toward OLA[454]). */
export const clamJobPromotionCost = (jobLevel) => 1e5 * Math.pow(10, Number(jobLevel ?? 0));

/** ClamPromochance(jobLevel) — chance the promotion roll succeeds once the cost is paid. */
export const clamPromoChance = (jobLevel) => 0.5 / (2 + Number(jobLevel ?? 0));

/** Clamz_HP(jobLevel) — enemy HP in the Clam Work minigame. */
export const clamzHp = (jobLevel) => 1e16 * Math.pow(30, Number(jobLevel ?? 0));

/** Clam_Mobs(upgLevel1) — max simultaneous clams on the map (upgLevel1 = OptLacc[456]). */
export const clamMobs = (upgLevel1) => Math.min(25, 2 + Number(upgLevel1 ?? 0));

/** Clam_Respawn() — constant, seconds between clam respawns. */
export const CLAM_RESPAWN_SEC = 60;
